"use strict";(self.webpackChunkzhishi=self.webpackChunkzhishi||[]).push([[6683],{8238:(n,s,a)=>{a.r(s),a.d(s,{data:()=>p});const p={key:"v-efda4a58",path:"/fe/js/new%20%E5%85%B3%E9%94%AE%E5%AD%97.html",title:"手写实现 new",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"new 做了什么",slug:"new-做了什么",children:[]},{level:2,title:"模拟代码实现",slug:"模拟代码实现",children:[{level:3,title:"初次实现",slug:"初次实现",children:[]},{level:3,title:"返回值效果实现",slug:"返回值效果实现",children:[]},{level:3,title:"完整版代码",slug:"完整版代码",children:[]}]},{level:2,title:"参考",slug:"参考",children:[]}],filePathRelative:"fe/js/new 关键字.md",git:{updatedTime:1627628114e3,contributors:[{name:"tangxue",email:"11183504@qq.com",commits:1}]}}},6388:(n,s,a)=>{a.r(s),a.d(s,{default:()=>c});var p=a(6252);const e=(0,p.uE)('<h1 id="手写实现-new" tabindex="-1"><a class="header-anchor" href="#手写实现-new" aria-hidden="true">#</a> 手写实现 new</h1><p>一句介绍 new</p><blockquote><p>new 运算符创建一个用户定义的对象类型的实例或具有构造函数的内置对象类型之一</p></blockquote><h2 id="new-做了什么" tabindex="-1"><a class="header-anchor" href="#new-做了什么" aria-hidden="true">#</a> new 做了什么</h2><ul><li><p>创建了一个全新的对象</p></li><li><p>这个对象会被执行<code>[[Prototype]]</code>连接，也就是 <code>__proto__</code> 连接</p></li><li><p>生成的新对象会绑定到函数调用的 <code>this</code></p></li><li><p>通过 new 创建的对象，最终被 <code>__proto__</code> 连接连接到这个函数的 <code>prototype</code> 对象上</p></li><li><p>如果构造函数没有返回对象类型 <code>Object</code>，如： <code>Functoin</code>, <code>Array</code>, <code>Date</code>, <code>RegExg</code>, <code>Error</code> 等， 那么 <code>new</code> 表达式中的函数调用会自动返回这个新的对象</p></li></ul><h2 id="模拟代码实现" tabindex="-1"><a class="header-anchor" href="#模拟代码实现" aria-hidden="true">#</a> 模拟代码实现</h2><p><strong>1. <code>new</code> 会创建的一个新的对象：</strong> 我们可以用 <code>new Object()</code> 创建一个新的对象：<code>obj</code></p><p><strong>2. 新对象会具有构造函数的属性：</strong> 可以用继承的方法，使用<code> Person.apply(obj, arguments)</code> 来给 <code>obj</code> 添加新的属性</p><p><strong>3. 新对象会具有构造函数的原型（<code>prototype</code>）的属性：</strong> 我们知道实例的 <strong>proto</strong> 属性会指向构造函数的 prototype，也正是因为这样的关系，实例可以访问原型上的属性</p><h3 id="初次实现" tabindex="-1"><a class="header-anchor" href="#初次实现" aria-hidden="true">#</a> 初次实现</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">newOperator</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  \n  <span class="token keyword">var</span> obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  \n  <span class="token keyword">var</span> Constructor <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token function">shift</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>arguments<span class="token punctuation">)</span>\n  \n  obj<span class="token punctuation">.</span>__proto__ <span class="token operator">=</span> <span class="token class-name">Constructor</span><span class="token punctuation">.</span>prototype\n  \n  <span class="token function">Constructor</span><span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">(</span>obj<span class="token punctuation">,</span> arguments<span class="token punctuation">)</span>\n  \n  <span class="token keyword">return</span> obj\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><ol><li><p>用 <code>new Object()</code> 创建新的对象</p></li><li><p>取出一个参数，就是我们传入的构造函数，此外使用 shft 会修改原来的数组，所以 <code>arguments</code> 会被取出第一个参数</p></li><li><p>将 obj 的原始指向构造函数，这样 obj 就可以访问到 构造函数的原型中的属性了</p></li><li><p>使用 apply 改变构造函数this的指向到新建的对象，这就就可以访问构造函数中的属性</p></li></ol><h3 id="返回值效果实现" tabindex="-1"><a class="header-anchor" href="#返回值效果实现" aria-hidden="true">#</a> 返回值效果实现</h3><ul><li><strong>构造函数返回一个对象</strong></li></ul><div class="custom-container tip"><p class="custom-container-title">提示</p><p>如果构造函数返回一个对象，那么在实例只能访问到返回的对象中的属性.</p><p>如果返回一个基本类型的值，就不会影响</p></div><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name<span class="token punctuation">,</span> age</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name\n  <span class="token keyword">this</span><span class="token punctuation">.</span>age <span class="token operator">=</span> age\n  \n  <span class="token keyword">return</span> <span class="token punctuation">{</span>\n    returnName<span class="token operator">:</span> name<span class="token punctuation">,</span>\n    say<span class="token operator">:</span> <span class="token string">&#39;德玛西亚&#39;</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n\n<span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">getName</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;名字：&#39;</span><span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">var</span> p1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&#39;盖伦&#39;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p1<span class="token punctuation">.</span>name<span class="token punctuation">)</span>          <span class="token comment">// undefined</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p1<span class="token punctuation">.</span>age<span class="token punctuation">)</span>           <span class="token comment">// undefined</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p1<span class="token punctuation">.</span>returnName<span class="token punctuation">)</span>    <span class="token comment">// 盖伦</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p1<span class="token punctuation">.</span>say<span class="token punctuation">)</span>           <span class="token comment">// 德玛西亚</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p1<span class="token punctuation">.</span><span class="token function">getName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>     <span class="token comment">// p1.getName is not a function （报错）</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><p>如果构造函数没有返回对象类型 <code>Object</code>，如： <code>Functoin</code>, <code>Array</code>, <code>Date</code>, <code>RegExg</code>, <code>Error</code> 等， 那么 <code>new</code> 表达式中的函数调用会自动返回这个新的对象</p><ul><li><strong>构造函数返回基础类型</strong></li></ul><p>基础类型返回值是正常的</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name<span class="token punctuation">,</span> age</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name\n  <span class="token keyword">this</span><span class="token punctuation">.</span>age <span class="token operator">=</span> age\n  \n  <span class="token keyword">return</span> <span class="token string">&#39;德玛西亚&#39;</span>\n<span class="token punctuation">}</span>\n\n<span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">getName</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;名字：&#39;</span><span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">var</span> p1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&#39;盖伦&#39;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p1<span class="token punctuation">.</span>name<span class="token punctuation">)</span>        <span class="token comment">// 盖伦</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p1<span class="token punctuation">.</span>age<span class="token punctuation">)</span>         <span class="token comment">// 18</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p1<span class="token punctuation">.</span><span class="token function">getName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>   <span class="token comment">// 名字： 盖伦</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>所以还要判断构造函数的返回值是不是一个对象，如果是一个对象，就返回这个对象，如果没有，该返回什么就什么</p><h3 id="完整版代码" tabindex="-1"><a class="header-anchor" href="#完整版代码" aria-hidden="true">#</a> 完整版代码</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">newOperator</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n\n  <span class="token comment">// 创建一个新的对象</span>\n  <span class="token keyword">var</span> obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  \n  <span class="token comment">// 获取外部传入的构造函数，并且删除第一次参数</span>\n  <span class="token keyword">var</span> Constructor <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token function">shift</span><span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">(</span>arguments<span class="token punctuation">)</span>\n  \n  <span class="token comment">// 用的 __proto__ 指向构造函数的原型，来获取原型的属性</span>\n  obj<span class="token punctuation">.</span>__proto__ <span class="token operator">=</span> <span class="token class-name">Constructor</span><span class="token punctuation">.</span>prototype\n  \n  <span class="token comment">// 继承构造函数的属性，并获取返回值</span>\n  <span class="token keyword">var</span> ret <span class="token operator">=</span> <span class="token function">Constructor</span><span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">(</span>obj<span class="token punctuation">,</span> arguments<span class="token punctuation">)</span>\n  \n  <span class="token comment">// 如果构造函数返回值是对象，就返回它，如果不是就返回 新对象</span>\n  <span class="token keyword">return</span> <span class="token keyword">typeof</span> ret <span class="token operator">===</span> <span class="token string">&#39;object&#39;</span> <span class="token operator">?</span> ret <span class="token operator">||</span> obj <span class="token operator">:</span> obj\n\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><h4 id="没有注释的" tabindex="-1"><a class="header-anchor" href="#没有注释的" aria-hidden="true">#</a> 没有注释的</h4><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">newOperator</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n\n  <span class="token keyword">var</span> obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  \n  <span class="token keyword">var</span> Constructor <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token function">shift</span><span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">(</span>arguments<span class="token punctuation">)</span>\n  \n  obj<span class="token punctuation">.</span>__proto__ <span class="token operator">=</span> <span class="token class-name">Constructor</span><span class="token punctuation">.</span>prototype\n  \n  <span class="token keyword">var</span> ret <span class="token operator">=</span> <span class="token function">Constructor</span><span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">(</span>obj<span class="token punctuation">,</span> arguments<span class="token punctuation">)</span>\n  \n  <span class="token keyword">return</span> <span class="token keyword">typeof</span> ret <span class="token operator">===</span> <span class="token string">&#39;object&#39;</span> <span class="token operator">?</span> ret <span class="token operator">||</span> obj <span class="token operator">:</span> obj\n\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>',26),t={href:"https://github.com/mqyqingfeng/Blog/issues/13",target:"_blank",rel:"noopener noreferrer"},o=(0,p.Uk)("JavaScript深入之new的模拟实现 #13"),c={render:function(n,s){const a=(0,p.up)("OutboundLink");return(0,p.wg)(),(0,p.j4)(p.HY,null,[e,(0,p.Wm)("p",null,[(0,p.Wm)("a",t,[o,(0,p.Wm)(a)])])],64)}}}}]);